export default {
  async fetch(request: Request, env: Env): Promise<Response> {
    try {
      return await routeRequest(request, env);
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      console.error("worker_error", message);
      return json({ ok: false, error: "internal_error", message }, 500);
    }
  }
};

async function routeRequest(request: Request, env: Env): Promise<Response> {
  const url = new URL(request.url);
  if (url.pathname.startsWith("/api/student/") && request.method === "OPTIONS") return handleStudentOptions();
  if (url.pathname.startsWith("/api/parent/") && request.method === "OPTIONS") return handleStudentOptions();
  if (url.pathname === "/health" && request.method === "GET") return json({ ok: true });
  if (url.pathname === "/manifest.webmanifest" && request.method === "GET") return handleManifest();
  if (url.pathname === "/service-worker.js" && request.method === "GET") return handleServiceWorker();
  if (url.pathname === "/sw.js" && request.method === "GET") return handleServiceWorker();
  if (url.pathname === "/app-icon.svg" && request.method === "GET") return handleAppIcon();
  if (url.pathname.startsWith("/visual-assets/") && request.method === "GET") return handleVisualAsset(url.pathname);
  const parentPwaResponse = await maybeHandleParentPwaStatic(request, env, url);
  if (parentPwaResponse) return parentPwaResponse;
  if (url.pathname === "/api/student/binding/code" && request.method === "GET") return handleStudentBindingCode(request, env);
  if (url.pathname === "/api/student/binding/refresh" && request.method === "POST") return handleStudentBindingRefresh(request, env);
  if (url.pathname === "/api/student/binding/status" && request.method === "GET") return handleStudentBindingStatus(env);
  if (url.pathname === "/api/student/binding/qr" && request.method === "GET") return handleStudentBindingQr(request);
  if (url.pathname === "/api/student/binding/mock-complete" && request.method === "POST") return handleStudentBindingMockComplete(env);
  if (url.pathname === "/api/student/binding/unbind" && request.method === "POST") return handleStudentBindingUnbind(env);
  if (url.pathname === "/api/student/permissions/status" && request.method === "GET") return handleStudentPermissionsStatus(env);
  if (url.pathname === "/api/student/permissions/report" && request.method === "POST") return handleStudentPermissionsReport(request, env);
  if (url.pathname === "/api/student/home/overview" && request.method === "GET") return handleStudentHomeOverview(env);
  if (url.pathname === "/api/student/guard/status" && request.method === "GET") return handleStudentGuardStatus(env);
  if (url.pathname === "/api/student/guard/start" && request.method === "POST") return handleStudentGuardStart(request, env);
  if (url.pathname === "/api/student/guard/end" && request.method === "POST") return handleStudentGuardEnd(env);
  if (url.pathname === "/api/student/guard/detail" && request.method === "GET") return handleStudentGuardDetail(env);
  if (url.pathname === "/api/student/whitelist" && request.method === "GET") return handleStudentWhitelist(env);
  if (url.pathname === "/api/student/whitelist/edit" && request.method === "GET") return handleStudentWhitelistEdit(env);
  if (url.pathname === "/api/student/apps/search" && request.method === "GET") return handleStudentAppsSearch(request, env);
  if (url.pathname === "/api/student/whitelist/add" && request.method === "POST") return handleStudentWhitelistAdd(request, env);
  if (url.pathname === "/api/student/whitelist/update" && request.method === "POST") return handleStudentWhitelistUpdate(request, env);
  if (url.pathname === "/api/student/release/apps" && request.method === "GET") return handleStudentReleaseApps(env);
  if (url.pathname === "/api/student/release/request" && request.method === "POST") return handleStudentReleaseRequestCreate(request, env);
  if (url.pathname === "/api/student/profile" && request.method === "GET") return handleStudentProfile(env);
  if (url.pathname === "/api/student/sync" && request.method === "POST") return handleStudentSync(request, env);
  if (url.pathname === "/api/parent/dashboard" && request.method === "GET") return handleParentDashboard(env);
  if (url.pathname === "/api/parent/approvals/pending" && request.method === "GET") return handleParentApprovalsPending(env);
  if (url.pathname === "/api/parent/approvals/recent" && request.method === "GET") return handleParentApprovalsRecent(env);
  if (url.pathname === "/api/parent/binding/confirm" && request.method === "POST") return handleParentBindingConfirm(request, env);
  if (url.pathname === "/api/parent/profile" && request.method === "GET") return handleParentProfile(env);
  if (url.pathname === "/welcome" && request.method === "GET") return handleWelcomePage(request, env);
  if (url.pathname === "/api/app/bootstrap" && request.method === "POST") return handleAppBootstrap(request, env);
  if (url.pathname === "/api/app/requests" && request.method === "POST") return handleAppCreateRequest(request, env);
  if (url.pathname === "/api/app/commands/next" && request.method === "GET") return handleAppNextCommand(request, env);
  if (url.pathname === "/activate" && request.method === "GET") return handleActivatePage(request, env);
  if (url.pathname === "/api/activate" && request.method === "POST") return handleActivateSubmit(request, env);
  if (url.pathname === "/login" && request.method === "GET") return handleLoginPage(request, env);
  if (url.pathname === "/api/login" && request.method === "POST") return handleLoginSubmit(request, env);
  if (url.pathname === "/api/logout" && request.method === "POST") return handleLogout();
  if (url.pathname === "/password" && request.method === "GET") return requireGuardianSession(request, env, () => handlePasswordPage());
  if (url.pathname === "/api/password" && request.method === "POST") return requireGuardianSession(request, env, () => handlePasswordSubmit(request, env));
  if (url.pathname === "/" && request.method === "GET") {
    const session = await getGuardianSession(request, env);
    if (!session) return redirect("/welcome");
    return handleParentPwaDashboard();
  }
  if (url.pathname === "/active" && request.method === "GET") return requireGuardianSession(request, env, () => handleActivePage(env));
  if (url.pathname === "/device" && request.method === "GET") return requireGuardianSession(request, env, () => handleDevicePage(request, env));
  if (url.pathname === "/requests" && request.method === "GET") return requireGuardianSession(request, env, () => handleParentPwaRequestsPage());
  if (url.pathname === "/rules" && request.method === "GET") return requireGuardianSession(request, env, () => handleRulesPage());
  if (url.pathname === "/report" && request.method === "GET") return requireGuardianSession(request, env, () => handleReportPage());
  if (url.pathname === "/me" && request.method === "GET") return requireGuardianSession(request, env, () => handleParentPwaMePage());

  const appStatusMatch = url.pathname.match(/^\/api\/app\/requests\/([^/]+)\/status$/);
  if (appStatusMatch && request.method === "GET") return handleAppRequestStatus(request, env, appStatusMatch[1]);
  const appCommandAppliedMatch = url.pathname.match(/^\/api\/app\/commands\/([^/]+)\/applied$/);
  if (appCommandAppliedMatch && request.method === "POST") return handleAppCommandApplied(request, env, appCommandAppliedMatch[1]);
  const studentReleaseMatch = url.pathname.match(/^\/api\/student\/release\/request\/([^/]+)$/);
  if (studentReleaseMatch && request.method === "GET") return handleStudentReleaseRequestStatus(env, studentReleaseMatch[1]);
  const studentReleaseCancelMatch = url.pathname.match(/^\/api\/student\/release\/request\/([^/]+)\/cancel$/);
  if (studentReleaseCancelMatch && request.method === "POST") return handleStudentReleaseRequestCancel(env, studentReleaseCancelMatch[1]);
  const parentApproveMatch = url.pathname.match(/^\/api\/parent\/approvals\/([^/]+)\/approve$/);
  if (parentApproveMatch && request.method === "POST") return handleParentApprovalApprove(request, env, parentApproveMatch[1]);
  const parentRejectMatch = url.pathname.match(/^\/api\/parent\/approvals\/([^/]+)\/reject$/);
  if (parentRejectMatch && request.method === "POST") return handleParentApprovalReject(request, env, parentRejectMatch[1]);
  const parentCommandMatch = url.pathname.match(/^\/api\/parent\/devices\/([^/]+)\/commands$/);
  if (parentCommandMatch && request.method === "POST") return handleParentCreateCommand(request, env, parentCommandMatch[1]);
  if (parentCommandMatch && request.method === "GET") return handleParentDeviceCommands(env, parentCommandMatch[1]);
  const parentRulesMatch = url.pathname.match(/^\/api\/parent\/devices\/([^/]+)\/rules$/);
  if (parentRulesMatch && request.method === "GET") return handleParentDeviceRules(env, parentRulesMatch[1]);
  const approveMatch = url.pathname.match(/^\/api\/guardian\/requests\/([^/]+)\/approve$/);
  if (approveMatch && request.method === "POST") return requireGuardianSession(request, env, () => handleApprove(request, env, approveMatch[1]));
  const rejectMatch = url.pathname.match(/^\/api\/guardian\/requests\/([^/]+)\/reject$/);
  if (rejectMatch && request.method === "POST") return requireGuardianSession(request, env, () => handleReject(request, env, rejectMatch[1]));
  const commandMatch = url.pathname.match(/^\/api\/guardian\/devices\/([^/]+)\/commands$/);
  if (commandMatch && request.method === "POST") return requireGuardianSession(request, env, () => handleGuardianCreateCommand(request, env, commandMatch[1]));
  const requestPageMatch = url.pathname.match(/^\/request\/([^/]+)$/);
  if (requestPageMatch && request.method === "GET") return requireGuardianSession(request, env, () => handleRequestDetailPage(env, requestPageMatch[1]));

  return new Response("Not found", { status: 404, headers: CACHE_HEADERS });
}

async function maybeHandleParentPwaStatic(request: Request, env: Env, url: URL): Promise<Response | null> {
  if (request.method !== "GET") return null;
  if (url.pathname.startsWith("/api/")) return null;
  if (url.pathname.startsWith("/activate")) return null;
  if (url.pathname === "/password") return null;
  if (url.pathname === "/active") return null;
  if (url.pathname === "/device") return null;
  if (url.pathname.startsWith("/request/")) return null;

  const routeFile = PARENT_PWA_STATIC_ROUTES[url.pathname];
  const directAsset =
    url.pathname.startsWith("/assets/") ||
    url.pathname.endsWith(".html") ||
    url.pathname.endsWith(".css") ||
    url.pathname.endsWith(".js") ||
    url.pathname.endsWith(".png") ||
    url.pathname.endsWith(".jpg") ||
    url.pathname.endsWith(".jpeg") ||
    url.pathname.endsWith(".webp") ||
    url.pathname.endsWith(".svg");

  if (!routeFile && !directAsset) return null;

  if (routeFile && PARENT_PWA_PROTECTED_ROUTES.has(url.pathname) && !hasParentMockLoginCookie(request)) {
    return redirect(`/login?next=${encodeURIComponent(parentPwaNextPath(url.pathname) + url.search)}`);
  }

  const assetUrl = new URL(request.url);
  assetUrl.pathname = routeFile || url.pathname;
  return env.ASSETS.fetch(new Request(assetUrl.toString(), request));
}

function hasParentMockLoginCookie(request: Request): boolean {
  const cookie = request.headers.get("cookie") || "";
  const flags = cookie.split(";").map((item) => item.trim());
  return flags.includes("parent_logged_in=true") || flags.includes("parent_mock_logged_in=true");
}

function parentPwaNextPath(pathname: string): string {
  const map: Record<string, string> = {
    "/index": "/",
    "/index.html": "/",
    "/home": "/",
    "/home.html": "/",
    "/approval": "/requests",
    "/approval.html": "/requests",
    "/rules.html": "/rules",
    "/report.html": "/report",
    "/profile": "/me",
    "/profile.html": "/me"
  };
  return map[pathname] || pathname || "/";
}

function handleVisualAsset(pathname: string): Response {
  const name = pathname.slice('/visual-assets/'.length);
  const data = V9_IMAGE_ASSETS[name];
  if (!data) return new Response('Not found', { status: 404, headers: CACHE_HEADERS });
  const binary = atob(data);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i += 1) bytes[i] = binary.charCodeAt(i);
  return new Response(bytes, {
    headers: {
      'content-type': 'image/png',
      'Cache-Control': 'public, max-age=31536000, immutable'
    }
  });
}

