async function handleStudentReleaseRequestCreate(request: Request, env: Env): Promise<Response> {
  const body = await readJsonObject(request);
  const durationMinutes = clampStudentDurationMinutes(body.durationMinutes);
  const reason = safeString(body.reason);
  const appKey = safeString(body.appId) || safeString(body.packageName);
  if (!appKey || durationMinutes <= 0 || !reason) return studentJson({ ok: false, error: "invalid_release_request" }, 400);
  const apps = readStudentApps(await getStudentMockState(env));
  const app = apps.find((item) => item.appId === appKey || item.packageName === appKey);
  const appName = app?.name || safeString(body.appName) || safeString(body.targetLabel) || appKey;
  const appCategory = app?.category || safeString(body.appCategory) || "受限应用";
  const now = Date.now();
  const requestId = `REQ-${new Date(now).toISOString().slice(0, 10).replace(/-/g, "")}-${randomToken(3).toUpperCase()}`;
  await env.APP_LOCK_DB.prepare(`
    INSERT INTO student_mock_release_requests (
      id, app_id, app_name, app_category, duration_minutes, reason,
      status, submitted_at, decided_at, reject_reason, temporary_access_expire_at
    ) VALUES (?, ?, ?, ?, ?, ?, 'pending', ?, NULL, NULL, NULL)
  `).bind(requestId, app?.appId || appKey, appName, appCategory, durationMinutes, reason, now).run();
  await recordStudentEvent(env, "release_request", `申请临时放行：${appName} ${durationMinutes} 分钟`);
  const row = await getStudentReleaseRequest(env, requestId);
  return studentJson({ ok: true, ...studentReleasePayload(row!) });
}

