async function handleStudentSync(request: Request, env: Env): Promise<Response> {
  const body = await readJsonObject(request);
  const state = await getStudentMockState(env);
  const now = Date.now();
  const patch: Record<string, unknown> = { last_sync_at: now, updated_at: now };
  if (Array.isArray(body.permissions)) patch.permissions_json = JSON.stringify(normalizeStudentPermissions(body.permissions, readStudentPermissions(state)));
  if (Array.isArray(body.apps)) patch.apps_json = JSON.stringify(normalizeStudentApps(body.apps, readStudentApps(state)));
  if (Array.isArray(body.whitelist)) patch.whitelist_json = JSON.stringify(body.whitelist.map((item) => safeString(item)).filter(Boolean));
  if (isPlainRecord(body.device)) {
    patch.device_info_json = JSON.stringify(body.device);
    const deviceName = safeString(body.device.deviceName);
    const deviceModel = safeString(body.device.deviceModel);
    const deviceId = safeString(body.device.deviceId);
    if (deviceName) patch.device_name = deviceName;
    if (deviceModel) patch.device_model = deviceModel;
    if (deviceId) patch.device_id = deviceId;
  }
  if (isPlainRecord(body.guard)) {
    patch.local_guard_json = JSON.stringify(body.guard);
    const guardStatus = safeString(body.guard.guardStatus);
    const mode = safeString(body.guard.mode);
    const modeName = safeString(body.guard.modeName);
    const startTimeMs = numberOrNull(body.guard.startTimeMs);
    const endTimeMs = numberOrNull(body.guard.endTimeMs);
    patch.guard_status = guardStatus === "active" ? "active" : "inactive";
    patch.guard_mode = mode || "focus";
    patch.guard_mode_name = modeName || (mode === "blocklist_mode" ? "锁应用模式" : "专注守门");
    patch.guard_start_at = startTimeMs;
    patch.guard_end_at = endTimeMs;
  }
  if (isPlainRecord(body.service)) patch.service_status_json = JSON.stringify(body.service);
  if (isPlainRecord(body.diagnostics)) patch.diagnostics_json = JSON.stringify(body.diagnostics);
  await updateStudentState(env, patch);
  if (isPlainRecord(body.device)) await syncStudentDeviceCommandIdentity(env, body.device, state);
  await recordStudentEvent(env, "student_sync", "学生端同步状态");
  const next = await getStudentMockState(env);
  return studentJson({
    ok: true,
    serverTime: new Date(now).toISOString(),
    lastSyncTime: new Date(next.last_sync_at).toISOString(),
    guard: studentGuardSnapshot(next, readStudentApps(next)),
    pendingCommands: [],
    message: "联调版已接收同步；真实本机执行结果后续由 Android 服务上报。"
  });
}

