async function handleParentApprovalApprove(request: Request, env: Env, requestId: string): Promise<Response> {
  const body = await readParentObject(request);
  const row = await getStudentReleaseRequest(env, requestId);
  if (!row) return parentJson({ ok: false, success: false, error: "not_found", message: "申请不存在" }, 404);
  if (row.status !== "pending") return parentJson({ ok: false, success: false, error: "invalid_status", message: "只有待审批申请可以同意" }, 409);
  const approvedMinutes = clampStudentDurationMinutes(body.approvedMinutes ?? body.durationMinutes ?? body.requestMinutes ?? row.duration_minutes);
  const now = Date.now();
  await env.APP_LOCK_DB.prepare(`
    UPDATE student_mock_release_requests
    SET status = 'approved', decided_at = ?, temporary_access_expire_at = ?, reject_reason = NULL
    WHERE id = ? AND status = 'pending'
  `).bind(now, now + approvedMinutes * 60_000, requestId).run();
  await recordStudentEvent(env, "parent_approve_release", `家长同意临时放行申请：${requestId}`);
  const state = await getStudentMockState(env);
  const next = await getStudentReleaseRequest(env, requestId);
  return parentJson({
    ok: true,
    success: true,
    message: "已同意申请。本阶段只同步审批结果，不执行本地临时放行。",
    request: parentReleasePayload(next!, state, readStudentApps(state)),
    localGrantExecuted: false
  });
}

