async function handleParentCreateCommand(request: Request, env: Env, requestedDeviceId: string): Promise<Response> {
  const state = await getStudentMockState(env);
  const device = await ensureCommandDevice(env, state, requestedDeviceId);
  if (!device.ok) return parentJson({ ok: false, success: false, error: device.error, message: device.message }, device.status);
  const body = await readParentObject(request);
  const command = normalizeParentCommand(body);
  if (!command.ok) return parentJson({ ok: false, success: false, error: command.error, message: command.message }, 400);
  const existing = await env.APP_LOCK_DB.prepare(`
    SELECT * FROM device_commands
    WHERE device_id = ? AND command_type = ? AND COALESCE(target_package, '') = COALESCE(?, '') AND COALESCE(payload_text, '') = COALESCE(?, '') AND status = 'pending'
    LIMIT 1
  `).bind(device.device.id, command.commandType, command.targetPackage, command.payloadText).first<DeviceCommandRow>();

  let row = existing;
  if (!row) {
    const commandId = crypto.randomUUID();
    await env.APP_LOCK_DB.prepare(`
      INSERT INTO device_commands (id, device_id, command_type, target_package, payload_text, status, created_at, applied_at)
      VALUES (?, ?, ?, ?, ?, 'pending', ?, NULL)
    `).bind(commandId, device.device.id, command.commandType, command.targetPackage, command.payloadText, Date.now()).run();
    row = await env.APP_LOCK_DB.prepare("SELECT * FROM device_commands WHERE id = ?").bind(commandId).first<DeviceCommandRow>();
  }
  await recordStudentEvent(env, "parent_device_command", `家长下发设备命令：${command.commandType}`);
  return parentJson({
    ok: true,
    success: true,
    message: existing ? "已有相同待执行命令，未重复创建。" : "命令已进入学生端拉取链路。",
    command: parentCommandPayload(row!)
  });
}

async function handleParentDeviceCommands(env: Env, requestedDeviceId: string): Promise<Response> {
  const state = await getStudentMockState(env);
  const device = await ensureCommandDevice(env, state, requestedDeviceId, false);
  if (!device.ok) return parentJson({ ok: false, success: false, error: device.error, message: device.message, commands: [] }, device.status);
  const rows = await env.APP_LOCK_DB.prepare("SELECT * FROM device_commands WHERE device_id = ? ORDER BY created_at DESC LIMIT 50").bind(device.device.id).all<DeviceCommandRow>();
  return parentJson({ ok: true, deviceId: device.device.id, commands: (rows.results || []).map(parentCommandPayload) });
}

async function latestTimeRangesCommand(env: Env, deviceId: string, commandType: string): Promise<{ date: string; timeRanges: Array<{ startTime: string; endTime: string }>; commandStatus: string } | null> {
  const row = await env.APP_LOCK_DB.prepare(`
    SELECT * FROM device_commands
    WHERE device_id = ? AND command_type = ?
    ORDER BY created_at DESC
    LIMIT 1
  `).bind(deviceId, commandType).first<DeviceCommandRow>();
  if (!row || !row.payload_text) return null;
  try {
    const payload = JSON.parse(row.payload_text);
    const ranges = Array.isArray(payload.timeRanges)
      ? payload.timeRanges
      : Array.isArray(payload.blockedTimeRanges)
        ? payload.blockedTimeRanges
        : [];
    return {
      date: safeString(payload.date) || todayDateKey(),
      timeRanges: ranges
        .map((item: any) => ({ startTime: safeString(item?.startTime), endTime: safeString(item?.endTime) }))
        .filter((item: { startTime: string; endTime: string }) => isClockText(item.startTime) && isClockText(item.endTime)),
      commandStatus: parentCommandStatus(row)
    };
  } catch {
    return null;
  }
}

async function latestDailyTimeRanges(env: Env, deviceId: string): Promise<{ date: string; timeRanges: Array<{ startTime: string; endTime: string }>; commandStatus: string } | null> {
  return latestTimeRangesCommand(env, deviceId, "set_daily_time_ranges");
}

async function latestBlockedTimeRanges(env: Env, deviceId: string): Promise<{ date: string; timeRanges: Array<{ startTime: string; endTime: string }>; commandStatus: string } | null> {
  return latestTimeRangesCommand(env, deviceId, "set_blocked_time_ranges");
}

async function handleParentDeviceRules(env: Env, requestedDeviceId: string): Promise<Response> {
  const state = await getStudentMockState(env);
  const apps = readStudentApps(state);
  const guard = studentGuardSnapshot(state, apps);
  const device = await ensureCommandDevice(env, state, requestedDeviceId, false);
  const dailyTimeRanges = device.ok ? await latestDailyTimeRanges(env, device.device.id) : null;
  const blockedTimeRanges = device.ok ? await latestBlockedTimeRanges(env, device.device.id) : null;
  return parentJson({
    ok: true,
    deviceId: requestedDeviceId,
    childName: state.student_name,
    rules: {
      guardMode: {
        enabled: state.guard_status === "active",
        mode: state.guard_mode,
        modeName: state.guard_mode_name,
        endTime: state.guard_end_at ? new Date(state.guard_end_at).toISOString() : null,
        remainingSeconds: guard.remainingSeconds
      },
      whitelist: apps.filter((app) => app.allowed).map(parentAppPayload),
      blockedApps: apps.filter((app) => app.locked && !app.allowed).map(parentAppPayload),
      apps: apps.map(parentAppPayload),
      learningMode: {
        enabled: false,
        supported: false,
        message: "学习模式本阶段只展示入口，暂未下发到学生端本机规则。"
      },
      sleepPeriod: {
        enabled: false,
        supported: false,
        startTime: "22:00",
        endTime: "07:00",
        message: "睡眠时段本阶段只展示入口，暂未接入学生端本机定时执行。"
      },
      dailyTimeRanges: {
        enabled: Boolean(dailyTimeRanges && dailyTimeRanges.timeRanges.length && dailyTimeRanges.commandStatus !== "failed"),
        supported: true,
        date: dailyTimeRanges?.date || todayDateKey(),
        timeRanges: dailyTimeRanges?.timeRanges || [],
        commandStatus: dailyTimeRanges?.commandStatus || "none",
        message: "今日可用时间段会下发到学生端本机执行；命令状态以学生端回传为准。"
      },
      blockedTimeRanges: {
        enabled: Boolean(blockedTimeRanges && blockedTimeRanges.timeRanges.length && blockedTimeRanges.commandStatus !== "failed"),
        supported: true,
        date: blockedTimeRanges?.date || todayDateKey(),
        timeRanges: blockedTimeRanges?.timeRanges || [],
        commandStatus: blockedTimeRanges?.commandStatus || "none",
        message: "今日禁止使用时间段会下发到学生端本机执行；禁止时段内进入守门，其他时间默认可用。"
      },
      temporaryWhitelist: {
        enabled: true,
        supported: true,
        source: "student_release_requests",
        message: "临时放行当前只同步审批状态，真实本机临时放行后续单独接入。"
      },
      appGroups: parentAppGroups(apps)
    }
  });
}

