async function handleParentBindingConfirm(request: Request, env: Env): Promise<Response> {
  const body = await readParentObject(request);
  const bindingCode = safeString(body.bindingCode).trim().toUpperCase();
  if (!/^[A-Z0-9]{6}$/.test(bindingCode)) {
    return parentJson({
      ok: false,
      success: false,
      message: "请输入学生端显示的 6 位绑定码。"
    }, 400);
  }

  const state = await getStudentMockState(env);
  if (state.binding_status === "bound") {
    return parentJson({
      ok: false,
      success: false,
      message: "这台设备已绑定监管人。"
    }, 409);
  }
  if ((state.binding_code || "").toUpperCase() !== bindingCode) {
    return parentJson({
      ok: false,
      success: false,
      message: "绑定码不存在，请核对学生端显示的 6 位绑定码。"
    }, 404);
  }
  if (state.binding_expires_at <= Date.now()) {
    return parentJson({
      ok: false,
      success: false,
      message: "绑定码已过期，请在学生端刷新绑定码。"
    }, 410);
  }

  const now = Date.now();
  const guardianName = state.guardian_name || "妈妈";
  const guardianRelation = state.guardian_relation || "妈妈";
  await updateStudentState(env, {
    binding_status: "bound",
    guardian_name: guardianName,
    guardian_relation: guardianRelation,
    updated_at: now
  });
  await recordStudentEvent(env, "binding_bound", `家长端输入绑定码完成绑定：${bindingCode}`);
  const next = await getStudentMockState(env);
  return parentJson({
    ok: true,
    success: true,
    message: "绑定成功",
    data: {
      bindingStatus: "bound",
      studentName: next.student_name,
      deviceName: next.device_name,
      deviceId: next.device_id,
      guardianName,
      guardianRelation
    }
  });
}

function parentJson(payload: unknown, status = 200): Response {
  return json(payload, status, STUDENT_CORS_HEADERS);
}

async function readParentObject(request: Request): Promise<Record<string, unknown>> {
  const contentType = request.headers.get("content-type") || "";
  if (contentType.includes("application/x-www-form-urlencoded") || contentType.includes("multipart/form-data")) {
    const form = await request.formData();
    const body: Record<string, unknown> = {};
    for (const [key, value] of form.entries()) {
      body[key] = typeof value === "string" ? value : value.name;
    }
    return body;
  }
  return readJsonObject(request);
}

function readStudentObject(value: string | null): Record<string, unknown> {
  if (!value) return {};
  try {
    const parsed = JSON.parse(value);
    return isPlainRecord(parsed) ? parsed : {};
  } catch {
    return {};
  }
}

function parentAppPayload(app: StudentMockApp): Record<string, unknown> {
  return {
    appId: app.appId,
    name: app.name,
    appName: app.name,
    category: app.category,
    appCategory: app.category,
    packageName: app.packageName,
    appPackage: app.packageName,
    iconUrl: app.iconUrl,
    allowed: app.allowed,
    locked: app.locked
  };
}

function parentReleasePayload(row: StudentMockReleaseRequestRow, state: StudentMockStateRow, apps: StudentMockApp[]): Record<string, unknown> {
  const app = apps.find((item) => item.appId === row.app_id || item.name === row.app_name);
  const packageName = app?.packageName || row.app_id;
  return {
    requestId: row.id,
    id: row.id,
    requestType: "app_block",
    childId: state.id,
    childName: state.student_name,
    deviceId: state.device_id,
    deviceName: state.device_name,
    guardianName: state.guardian_name || "妈妈",
    appId: row.app_id,
    appName: row.app_name,
    appCategory: row.app_category,
    category: row.app_category,
    packageName,
    appPackage: packageName,
    durationMinutes: row.duration_minutes,
    requestMinutes: row.duration_minutes,
    reason: row.reason,
    requestReason: row.reason,
    status: row.status,
    statusText: parentReleaseStatusText(row.status),
    submittedAt: new Date(row.submitted_at).toISOString(),
    requestTime: new Date(row.submitted_at).toISOString(),
    submittedAtText: formatAppTime(row.submitted_at),
    decidedAt: row.decided_at ? new Date(row.decided_at).toISOString() : null,
    rejectReason: row.reject_reason,
    temporaryAccessExpireAt: row.temporary_access_expire_at ? new Date(row.temporary_access_expire_at).toISOString() : null
  };
}

function parentReleaseStatusText(status: string): string {
  if (status === "pending") return "等待审批";
  if (status === "approved") return "已同意";
  if (status === "rejected") return "已拒绝";
  if (status === "cancelled") return "已撤回";
  if (status === "expired") return "已过期";
  return status;
}

function parentGuardStatus(state: StudentMockStateRow, permissions: StudentPermissionItem[], service: Record<string, unknown>): { status: string; text: string; deviceText: string; online: boolean } {
  const now = Date.now();
  const monitorHeartbeat = numberOrZero(service.monitorHeartbeatAt);
  const accessibilityHeartbeat = numberOrZero(service.accessibilityHeartbeatAt);
  const lastActivity = Math.max(state.last_sync_at || 0, monitorHeartbeat, accessibilityHeartbeat);
  const online = lastActivity > 0 && now - lastActivity < 10 * 60_000;
  const missingRequired = permissions.some((item) => item.required && item.status !== "enabled");
  if (!online) return { status: "offline", text: "设备离线", deviceText: "设备暂时离线", online: false };
  if (missingRequired) return { status: "error", text: "权限异常", deviceText: "关键权限未完成", online: true };
  if (state.guard_status === "active") return { status: "locked", text: "锁定中", deviceText: "守门模式运行中", online: true };
  if (state.guard_status === "ended" || state.guard_status === "inactive") {
    return { status: "paused", text: "未开启守门", deviceText: "守门未开启", online: true };
  }
  const serviceAlive = Boolean(service.monitorAlive) || Boolean(service.accessibilityAlive);
  if (serviceAlive) return { status: "paused", text: "未开启守门", deviceText: "设备运行正常，守门未开启", online: true };
  return { status: "paused", text: "未锁定", deviceText: "守门未开启", online: true };
}

function numberOrZero(value: unknown): number {
  const numberValue = Number(value);
  return Number.isFinite(numberValue) ? numberValue : 0;
}

function parentAppGroups(apps: StudentMockApp[]): Array<Record<string, unknown>> {
  const groups = new Map<string, StudentMockApp[]>();
  for (const app of apps) {
    const groupName = app.category || "其他";
    groups.set(groupName, [...(groups.get(groupName) || []), app]);
  }
  return Array.from(groups.entries()).map(([groupName, groupApps]) => ({
    groupId: groupName,
    groupName,
    totalCount: groupApps.length,
    allowedCount: groupApps.filter((app) => app.allowed).length,
    apps: groupApps.map(parentAppPayload),
    source: "student_whitelist"
  }));
}

async function syncStudentDeviceCommandIdentity(env: Env, device: Record<string, unknown>, state: StudentMockStateRow): Promise<void> {
  const deviceId = safeString(device.deviceId);
  const deviceSecret = safeString(device.deviceSecret);
  if (!deviceId || !deviceSecret) return;
  const deviceName = safeString(device.deviceName) || state.device_name || "Student Device";
  const now = Date.now();
  const existing = await env.APP_LOCK_DB.prepare("SELECT id FROM app_devices WHERE id = ?").bind(deviceId).first<{ id: string }>();
  if (existing) {
    await env.APP_LOCK_DB.prepare("UPDATE app_devices SET device_secret = ?, device_name = ?, last_seen_at = ? WHERE id = ?").bind(deviceSecret, deviceName, now, deviceId).run();
  } else {
    await env.APP_LOCK_DB.prepare("INSERT INTO app_devices (id, device_secret, device_name, created_at, last_seen_at) VALUES (?, ?, ?, ?, ?)").bind(deviceId, deviceSecret, deviceName, now, now).run();
  }
}

async function ensureCommandDevice(env: Env, state: StudentMockStateRow, requestedDeviceId: string, createFromStudent = true): Promise<
  | { ok: true; device: DeviceRow }
  | { ok: false; status: number; error: string; message: string }
> {
  const deviceInfo = readStudentObject(state.device_info_json);
  const syncedDeviceId = safeString(deviceInfo.deviceId) || state.device_id;
  const requested = safeString(requestedDeviceId);
  if (createFromStudent && syncedDeviceId && safeString(deviceInfo.deviceSecret)) {
    await syncStudentDeviceCommandIdentity(env, deviceInfo, state);
  }
  const candidateIds = Array.from(new Set([requested, syncedDeviceId, state.device_id].filter(Boolean)));
  for (const candidateId of candidateIds) {
    const device = await env.APP_LOCK_DB.prepare("SELECT * FROM app_devices WHERE id = ?").bind(candidateId).first<DeviceRow>();
    if (device) return { ok: true, device };
  }
  if (!safeString(deviceInfo.deviceSecret)) {
    return {
      ok: false,
      status: 409,
      error: "device_command_identity_missing",
      message: "学生端还没有上报 deviceSecret，家长端不能生成可执行命令。请先让学生端完成一次 /api/student/sync。"
    };
  }
  return { ok: false, status: 404, error: "device_not_found", message: "设备不存在或尚未完成命令链路绑定。" };
}

function normalizeParentCommand(body: Record<string, unknown>): { ok: true; commandType: string; targetPackage: string | null; payloadText: string | null } | { ok: false; error: string; message: string } {
  const rawType = safeString(body.commandType) || safeString(body.type);
  let commandType = rawType;
  let targetPackage = nullableString(body.targetPackage ?? body.packageName ?? body.appPackage);
  let payloadText = nullableString(body.payloadText ?? body.payload ?? body.minutes ?? body.durationMinutes);
  if (rawType === "one_key_lock" || rawType === "lock_device" || rawType === "start_guard_mode" || rawType === "temporary_lock" || rawType === "global_guard") {
    commandType = "start_guard_mode_custom";
    payloadText = String(clampParentCommandMinutes(body.durationMinutes ?? body.minutes ?? body.payloadText ?? 30));
  }
  if (rawType === "end_guard_mode" || rawType === "unlock_device" || rawType === "cancel_guard_mode") commandType = "stop_guard_mode";
  if (rawType === "block_app") commandType = "app_block";
  if (rawType === "unblock_app") commandType = "app_unblock";
  if (rawType === "set_today_limit") {
    return { ok: false, error: "unsupported_command", message: "今日可用总时长本阶段只展示，不下发学生端命令。" };
  }
  if (rawType === "set_daily_time_ranges") {
    const normalized = normalizeDailyTimeRangesPayload(body);
    if (!normalized.ok) return normalized;
    commandType = "set_daily_time_ranges";
    targetPackage = null;
    payloadText = JSON.stringify(normalized.payload);
  }
  if (rawType === "set_blocked_time_ranges") {
    const normalized = normalizeBlockedTimeRangesPayload(body);
    if (!normalized.ok) return normalized;
    commandType = "set_blocked_time_ranges";
    targetPackage = null;
    payloadText = JSON.stringify(normalized.payload);
  }
  const allowed = new Set([
    "start_guard_mode_30",
    "start_guard_mode_60",
    "start_guard_mode_120",
    "start_guard_mode_custom",
    "stop_guard_mode",
    "set_guard_whitelist",
    "set_daily_time_ranges",
    "set_blocked_time_ranges",
    "app_block",
    "app_unblock",
    "enable_risk_shield",
    "disable_risk_shield",
    "show_launcher",
    "hide_launcher"
  ]);
  if (!allowed.has(commandType)) return { ok: false, error: "unsupported_command", message: "学生端当前不能识别这个命令类型，已拒绝生成孤立命令。" };
  if (commandType === "start_guard_mode_custom") {
    const minutes = clampParentCommandMinutes(payloadText);
    if (minutes <= 0) return { ok: false, error: "invalid_minutes", message: "自定义守门时间必须是 1 到 1440 分钟。" };
    payloadText = String(minutes);
  }
  if (commandType === "set_guard_whitelist") {
    payloadText = safeString(body.payloadText) || safeString(body.packageNames) || safeString(body.packages) || payloadText;
    if (!payloadText) return { ok: false, error: "empty_whitelist", message: "白名单命令必须包含包名列表。" };
  }
  if (commandType === "app_block" || commandType === "app_unblock") {
    if (!targetPackage || !targetPackage.includes(".") || targetPackage.length < 3) {
      return { ok: false, error: "invalid_package", message: "请选择要控制的具体应用。" };
    }
    payloadText = null;
  }
  if (!targetPackage) targetPackage = null;
  if (!payloadText) payloadText = null;
  return { ok: true, commandType, targetPackage, payloadText };
}

function clampParentCommandMinutes(value: unknown): number {
  const minutes = Number.parseInt(String(value ?? ""), 10);
  if (!Number.isFinite(minutes) || minutes < 1 || minutes > 1440) return 0;
  return minutes;
}

function todayDateKey(): string {
  const parts = new Intl.DateTimeFormat("en-CA", {
    timeZone: "Asia/Shanghai",
    year: "numeric",
    month: "2-digit",
    day: "2-digit"
  }).formatToParts(new Date());
  const year = parts.find((item) => item.type === "year")?.value || "1970";
  const month = parts.find((item) => item.type === "month")?.value || "01";
  const day = parts.find((item) => item.type === "day")?.value || "01";
  return `${year}-${month}-${day}`;
}

function isClockText(value: string): boolean {
  return /^([01]\d|2[0-3]):[0-5]\d$/.test(value);
}

function clockToMinute(value: string): number {
  if (!isClockText(value)) return 0;
  const [hour, minute] = value.split(":").map((part) => Number.parseInt(part, 10));
  return hour * 60 + minute;
}

function currentChinaMinuteOfDay(): number {
  const parts = new Intl.DateTimeFormat("en-GB", {
    timeZone: "Asia/Shanghai",
    hour: "2-digit",
    minute: "2-digit",
    hourCycle: "h23"
  }).formatToParts(new Date());
  const hour = Number.parseInt(parts.find((item) => item.type === "hour")?.value || "0", 10);
  const minute = Number.parseInt(parts.find((item) => item.type === "minute")?.value || "0", 10);
  return hour * 60 + minute;
}

function dailyTimeRangeUsage(rule: { date: string; timeRanges: Array<{ startTime: string; endTime: string }>; commandStatus: string } | null): { usedMinutes: number; totalMinutes: number; remainingMinutes: number; unlockCount: number; source: string } {
  if (!rule || rule.commandStatus === "failed" || rule.date !== todayDateKey() || !rule.timeRanges.length) {
    return {
      usedMinutes: 0,
      totalMinutes: 180,
      remainingMinutes: 0,
      unlockCount: 0,
      source: "mock"
    };
  }
  const nowMinute = currentChinaMinuteOfDay();
  let totalMinutes = 0;
  let elapsedMinutes = 0;
  for (const range of rule.timeRanges) {
    const start = clockToMinute(range.startTime);
    const end = clockToMinute(range.endTime);
    const duration = start === end ? 24 * 60 : (end > start ? end - start : 24 * 60 - start + end);
    totalMinutes += duration;
    if (start === end) {
      elapsedMinutes += nowMinute;
    } else if (end > start) {
      elapsedMinutes += Math.max(0, Math.min(nowMinute, end) - start);
    } else {
      elapsedMinutes += nowMinute >= start ? nowMinute - start : Math.max(0, nowMinute);
    }
  }
  const usedMinutes = Math.max(0, Math.min(elapsedMinutes, totalMinutes));
  return {
    usedMinutes,
    totalMinutes,
    remainingMinutes: Math.max(0, totalMinutes - usedMinutes),
    unlockCount: 0,
    source: "daily_time_ranges"
  };
}

function blockedTimeRangeUsage(rule: { date: string; timeRanges: Array<{ startTime: string; endTime: string }>; commandStatus: string } | null): { usedMinutes: number; totalMinutes: number; remainingMinutes: number; unlockCount: number; source: string } {
  if (!rule || rule.commandStatus === "failed" || rule.date !== todayDateKey() || !rule.timeRanges.length) {
    return {
      usedMinutes: 0,
      totalMinutes: 1440,
      remainingMinutes: 1440,
      unlockCount: 0,
      source: "blocked_time_ranges_empty"
    };
  }
  const nowMinute = currentChinaMinuteOfDay();
  let blockedTotal = 0;
  let blockedElapsed = 0;
  for (const range of rule.timeRanges) {
    const start = clockToMinute(range.startTime);
    const end = clockToMinute(range.endTime);
    const duration = start === end ? 24 * 60 : (end > start ? end - start : 24 * 60 - start + end);
    blockedTotal += duration;
    if (start === end) {
      blockedElapsed += nowMinute;
    } else if (end > start) {
      blockedElapsed += Math.max(0, Math.min(nowMinute, end) - start);
    } else {
      blockedElapsed += nowMinute >= start ? nowMinute - start : Math.max(0, nowMinute);
    }
  }
  const totalMinutes = Math.max(0, Math.min(24 * 60, (24 * 60) - blockedTotal));
  const usedMinutes = Math.max(0, Math.min(totalMinutes, nowMinute - Math.max(0, Math.min(nowMinute, blockedElapsed))));
  return {
    usedMinutes,
    totalMinutes,
    remainingMinutes: Math.max(0, totalMinutes - usedMinutes),
    unlockCount: 0,
    source: "blocked_time_ranges"
  };
}

function normalizeDailyTimeRangesPayload(body: Record<string, unknown>): { ok: true; payload: { date: string; timeRanges: Array<{ startTime: string; endTime: string }> } } | { ok: false; error: string; message: string } {
  const date = safeString(body.date) || todayDateKey();
  if (!/^\d{4}-\d{2}-\d{2}$/.test(date)) {
    return { ok: false, error: "invalid_date", message: "请选择正确的日期。" };
  }
  const rawRanges = Array.isArray(body.timeRanges) ? body.timeRanges : [];
  const timeRanges = rawRanges
    .map((item: any) => ({
      startTime: safeString(item?.startTime ?? item?.start),
      endTime: safeString(item?.endTime ?? item?.end)
    }))
    .filter((item: { startTime: string; endTime: string }) => isClockText(item.startTime) && isClockText(item.endTime));
  if (!timeRanges.length) {
    return { ok: false, error: "empty_time_ranges", message: "请至少填写一个可用时间段。" };
  }
  if (timeRanges.length > 6) {
    return { ok: false, error: "too_many_time_ranges", message: "每日可用时间段最多设置 6 段。" };
  }
  return { ok: true, payload: { date, timeRanges } };
}

function normalizeBlockedTimeRangesPayload(body: Record<string, unknown>): { ok: true; payload: { date: string; timeRanges: Array<{ startTime: string; endTime: string }>; blockedTimeRanges: Array<{ startTime: string; endTime: string }>; ruleType: string } } | { ok: false; error: string; message: string } {
  const date = safeString(body.date) || todayDateKey();
  if (!/^\d{4}-\d{2}-\d{2}$/.test(date)) {
    return { ok: false, error: "invalid_date", message: "请选择正确的日期。" };
  }
  const rawRanges = Array.isArray(body.blockedTimeRanges)
    ? body.blockedTimeRanges
    : Array.isArray(body.timeRanges)
      ? body.timeRanges
      : [];
  const timeRanges = rawRanges
    .map((item: any) => ({
      startTime: safeString(item?.startTime ?? item?.start),
      endTime: safeString(item?.endTime ?? item?.end)
    }))
    .filter((item: { startTime: string; endTime: string }) => isClockText(item.startTime) && isClockText(item.endTime));
  if (timeRanges.length > 8) {
    return { ok: false, error: "too_many_time_ranges", message: "今日禁止时间段最多设置 8 段。" };
  }
  return {
    ok: true,
    payload: {
      date,
      timeRanges,
      blockedTimeRanges: timeRanges,
      ruleType: "blocked"
    }
  };
}

function parentCommandPayload(row: DeviceCommandRow): Record<string, unknown> {
  return {
    commandId: row.id,
    id: row.id,
    deviceId: row.device_id,
    commandType: row.command_type,
    commandLabel: commandTypeLabel(row.command_type),
    targetPackage: row.target_package,
    payloadText: row.payload_text,
    rawStatus: row.status,
    commandStatus: parentCommandStatus(row),
    resultStatus: row.result_status,
    resultMessage: row.result_message,
    createdAt: new Date(row.created_at).toISOString(),
    appliedAt: row.applied_at ? new Date(row.applied_at).toISOString() : null
  };
}

function parentCommandStatus(row: DeviceCommandRow): string {
  if (row.status === "pending") {
    return Date.now() - row.created_at > 30 * 60_000 ? "timeout" : "pending";
  }
  if (row.status === "applied" && row.result_status === "failed") return "failed";
  if (row.status === "applied") return "success";
  return row.status || "pending";
}

async function handleAppBootstrap(request: Request, env: Env): Promise<Response> {
  const body = await readJsonObject(request);
  const deviceId = safeString(body.deviceId);
  const deviceSecret = safeString(body.deviceSecret);
  const deviceName = safeString(body.deviceName) || "Android Device";
  if (!deviceId || !deviceSecret) return json({ ok: false, error: "missing_device_credentials" }, 400);

  const existing = await env.APP_LOCK_DB.prepare("SELECT id, device_secret FROM app_devices WHERE id = ?").bind(deviceId).first<DeviceRow>();
  const now = Date.now();
  if (existing) {
    if (existing.device_secret !== deviceSecret) return json({ ok: false, error: "invalid_device_secret" }, 403);
    await env.APP_LOCK_DB.prepare("UPDATE app_devices SET device_name = ?, last_seen_at = ? WHERE id = ?").bind(deviceName, now, deviceId).run();
  } else {
    await env.APP_LOCK_DB.prepare("INSERT INTO app_devices (id, device_secret, device_name, created_at, last_seen_at) VALUES (?, ?, ?, ?, ?)").bind(deviceId, deviceSecret, deviceName, now, now).run();
  }

  const guardianConfigured = await hasGuardianAccount(env);
  return json({
    ok: true,
    guardianConfigured,
    dashboardUrl: baseUrl(request),
    activationUrl: guardianConfigured ? null : `${baseUrl(request)}/activate?token=${encodeURIComponent(env.SETUP_TOKEN)}`
  });
}

async function handleAppCreateRequest(request: Request, env: Env): Promise<Response> {
  const body = await readJsonObject(request);
  const deviceId = safeString(body.deviceId);
  const deviceSecret = safeString(body.deviceSecret);
  const requestType = safeString(body.requestType);
  const requestedMinutes = clampMinutes(body.requestedMinutes);
  const requestReason = nullableString(body.requestReason);
  if (!deviceId || !deviceSecret || !requestType || requestedMinutes <= 0) return json({ ok: false, error: "invalid_request" }, 400);

  const device = await authenticateDevice(env, deviceId, deviceSecret);
  if (!device) return json({ ok: false, error: "unauthorized_device" }, 403);

  const targetPackage = nullableString(body.targetPackage);
  const pending = requestType === "unlock_app"
    ? await env.APP_LOCK_DB.prepare("SELECT id FROM unlock_requests WHERE device_id = ? AND request_type = ? AND target_package = ? AND status = 'pending' LIMIT 1").bind(device.id, requestType, targetPackage).first<{ id: string }>()
    : await env.APP_LOCK_DB.prepare("SELECT id FROM unlock_requests WHERE device_id = ? AND request_type = ? AND status = 'pending' LIMIT 1").bind(device.id, requestType).first<{ id: string }>();
  if (pending) return json({ ok: true, requestId: pending.id, reused: true });

  const requestId = crypto.randomUUID();
  await env.APP_LOCK_DB.prepare(`
    INSERT INTO unlock_requests (
      id, device_id, request_type, target_package, target_label,
      requested_minutes, request_reason, status, approved_minutes, approved_mode, guardian_note, created_at, decided_at
    ) VALUES (?, ?, ?, ?, ?, ?, ?, 'pending', NULL, NULL, NULL, ?, NULL)
  `).bind(requestId, device.id, requestType, targetPackage, nullableString(body.targetLabel), requestedMinutes, requestReason, Date.now()).run();
  return json({ ok: true, requestId, reused: false });
}

async function handleAppRequestStatus(request: Request, env: Env, requestId: string): Promise<Response> {
  const url = new URL(request.url);
  const device = await authenticateDevice(env, safeString(url.searchParams.get("deviceId")), safeString(url.searchParams.get("deviceSecret")));
  if (!device) return json({ ok: false, error: "unauthorized_device" }, 403);
  const row = await env.APP_LOCK_DB.prepare("SELECT id, status, approved_minutes, approved_mode, decided_at, guardian_note FROM unlock_requests WHERE id = ? AND device_id = ?").bind(requestId, device.id).first<any>();
  if (!row) return json({ ok: false, error: "not_found" }, 404);
  return json({ ok: true, requestId: row.id, status: row.status, approvedMinutes: row.approved_minutes ?? 0, approvedMode: row.approved_mode ?? "minutes", decidedAt: row.decided_at, guardianNote: row.guardian_note });
}

async function handleAppNextCommand(request: Request, env: Env): Promise<Response> {
  const url = new URL(request.url);
  const device = await authenticateDevice(env, safeString(url.searchParams.get("deviceId")), safeString(url.searchParams.get("deviceSecret")));
  if (!device) return json({ ok: false, error: "unauthorized_device" }, 403);
  const row = await env.APP_LOCK_DB.prepare("SELECT id, command_type, target_package, payload_text, created_at FROM device_commands WHERE device_id = ? AND status = 'pending' ORDER BY created_at ASC LIMIT 1").bind(device.id).first<any>();
  if (!row) return json({ ok: true, hasCommand: false });
  return json({ ok: true, hasCommand: true, commandId: row.id, commandType: row.command_type, targetPackage: row.target_package, payloadText: row.payload_text, createdAt: row.created_at });
}

async function handleAppCommandApplied(request: Request, env: Env, commandId: string): Promise<Response> {
  const body = await readJsonObject(request);
  const device = await authenticateDevice(env, safeString(body.deviceId), safeString(body.deviceSecret));
  if (!device) return json({ ok: false, error: "unauthorized_device" }, 403);
  const resultStatus = safeString(body.resultStatus) || "success";
  const resultMessage = nullableString(body.resultMessage);
  await env.APP_LOCK_DB.prepare("UPDATE device_commands SET status = 'applied', result_status = ?, result_message = ?, applied_at = ? WHERE id = ? AND device_id = ? AND status = 'pending'").bind(resultStatus, resultMessage, Date.now(), commandId, device.id).run();
  return json({ ok: true });
}

