async function handleActivateSubmit(request: Request, env: Env): Promise<Response> {
  if (await hasGuardianAccount(env)) return redirect("/login");
  const form = await request.formData();
  const token = safeString(form.get("token"));
  const username = safeString(form.get("username"));
  const password = safeString(form.get("password"));
  const confirmPassword = safeString(form.get("confirmPassword"));
  if (token !== env.SETUP_TOKEN) return html(pageShell("激活失败", renderMessageCard("激活链接无效", "请从手机端重新生成监管网页激活链接。")), 403);
  if (!username || password.length < 8 || password !== confirmPassword) return html(pageShell("激活失败", renderMessageCard("请检查用户名和密码", "密码至少 8 位，并且两次输入要一致。", `<a class="button-link" href="/activate?token=${encodeURIComponent(token)}">返回激活</a>`)), 400);

  const salt = randomToken(16);
  const hash = await hashPassword(password, salt);
  const now = Date.now();
  await env.APP_LOCK_DB.prepare("INSERT INTO guardian_account (id, username, password_hash, password_salt, created_at, updated_at) VALUES (1, ?, ?, ?, ?, ?)").bind(username, hash, salt, now, now).run();
  return redirect("/login");
}

