async function handlePasswordSubmit(request: Request, env: Env): Promise<Response> {
  const account = await env.APP_LOCK_DB.prepare("SELECT id, username, password_hash, password_salt, created_at, updated_at FROM guardian_account WHERE id = 1").first<GuardianAccountRow>();
  if (!account) return html(pageShell("修改失败", renderMessageCard("监管人账号不存在", "请先完成首次激活。")), 400);
  const form = await request.formData();
  const currentPassword = safeString(form.get("currentPassword"));
  const newPassword = safeString(form.get("newPassword"));
  const confirmPassword = safeString(form.get("confirmPassword"));
  const currentHash = await hashPassword(currentPassword, account.password_salt);
  if (currentHash !== account.password_hash) return html(pageShell("修改失败", renderMessageCard("旧密码不正确", "请返回后重新输入。", `<a class="button-link" href="/password">返回修改</a>`), { authenticated: true, activeNav: "me" }), 403);
  if (newPassword.length < 8 || newPassword !== confirmPassword) return html(pageShell("修改失败", renderMessageCard("新密码不符合要求", "新密码至少 8 位，并且两次输入要一致。", `<a class="button-link" href="/password">返回修改</a>`), { authenticated: true, activeNav: "me" }), 400);

  const salt = randomToken(16);
  const hash = await hashPassword(newPassword, salt);
  await env.APP_LOCK_DB.prepare("UPDATE guardian_account SET password_hash = ?, password_salt = ?, updated_at = ? WHERE id = 1").bind(hash, salt, Date.now()).run();
  return html(pageShell("修改成功", renderMessageCard("密码已更新", "下次登录请使用新密码。", `<div class="button-row"><a class="button-link primary" href="/me">回到我的</a><a class="button-link" href="/">回到首页</a></div>`), { authenticated: true, activeNav: "me" }));
}

