async function loadGuardianData(env: Env): Promise<GuardianData> {
  const pendingRows = await env.APP_LOCK_DB.prepare(`
    SELECT unlock_requests.*, app_devices.device_name
    FROM unlock_requests
    JOIN app_devices ON app_devices.id = unlock_requests.device_id
    WHERE unlock_requests.status = 'pending'
      AND unlock_requests.device_id = (SELECT id FROM app_devices ORDER BY last_seen_at DESC LIMIT 1)
    ORDER BY unlock_requests.created_at DESC
    LIMIT 20
  `).all<UnlockRequestRow>();

  const recentRows = await env.APP_LOCK_DB.prepare(`
    SELECT unlock_requests.*, app_devices.device_name
    FROM unlock_requests
    JOIN app_devices ON app_devices.id = unlock_requests.device_id
    WHERE unlock_requests.device_id = (SELECT id FROM app_devices ORDER BY last_seen_at DESC LIMIT 1)
    ORDER BY unlock_requests.created_at DESC
    LIMIT 80
  `).all<UnlockRequestRow>();

  const devices = await env.APP_LOCK_DB.prepare("SELECT id, device_secret, device_name, created_at, last_seen_at FROM app_devices ORDER BY last_seen_at DESC LIMIT 20").all<DeviceRow>();
  const commandRows = await env.APP_LOCK_DB.prepare(`
    SELECT device_commands.*, app_devices.device_name
    FROM device_commands
    JOIN app_devices ON app_devices.id = device_commands.device_id
    WHERE device_commands.device_id = (SELECT id FROM app_devices ORDER BY last_seen_at DESC LIMIT 1)
    ORDER BY device_commands.created_at DESC
    LIMIT 50
  `).all<DeviceCommandRow>();

  const recent = recentRows.results || [];
  const approvedRows = recent.filter((row) => row.status === "approved");
  const rejectedRows = recent.filter((row) => row.status === "rejected");
  return {
    pendingRows: pendingRows.results || [],
    recentRows: recent,
    approvedRows,
    rejectedRows,
    activeApprovedRows: approvedRows.filter(isApprovalStillActive),
    devices: devices.results || [],
    commandRows: commandRows.results || []
  };
}

async function loadRequestById(env: Env, requestId: string): Promise<UnlockRequestRow | null> {
  return await env.APP_LOCK_DB.prepare(`
    SELECT unlock_requests.*, app_devices.device_name
    FROM unlock_requests
    JOIN app_devices ON app_devices.id = unlock_requests.device_id
    WHERE unlock_requests.id = ?
    LIMIT 1
  `).bind(requestId).first<UnlockRequestRow>();
}

async function handleApprove(request: Request, env: Env, requestId: string): Promise<Response> {
  const form = await request.formData();
  const approvedMode = safeString(form.get("approvedMode")) || "minutes";
  const guardianNote = nullableString(form.get("guardianNote"));
  const returnTo = safeReturnPath(form.get("returnTo"), "/");
  let approvedMinutes: number | null = null;
  let normalizedMode = "minutes";

  if (approvedMode === "today") {
    normalizedMode = "today";
  } else {
    approvedMinutes = clampMinutes(form.get("approvedMinutes"));
    if (!approvedMinutes) return html(pageShell("审批失败", renderMessageCard("批准时长无效", "请返回后重新选择时长。", `<a class="button-link" href="/">返回首页</a>`), { authenticated: true, activeNav: "home" }), 400);
  }

  await env.APP_LOCK_DB.prepare(`
    UPDATE unlock_requests
    SET status = 'approved', approved_minutes = ?, approved_mode = ?, guardian_note = ?, decided_at = ?
    WHERE id = ? AND status = 'pending'
  `).bind(approvedMinutes, normalizedMode, guardianNote, Date.now(), requestId).run();
  return redirect(returnTo);
}

async function handleReject(request: Request, env: Env, requestId: string): Promise<Response> {
  const form = await request.formData();
  const guardianNote = nullableString(form.get("guardianNote"));
  const returnTo = safeReturnPath(form.get("returnTo"), "/");
  await env.APP_LOCK_DB.prepare("UPDATE unlock_requests SET status = 'rejected', guardian_note = ?, decided_at = ? WHERE id = ? AND status = 'pending'").bind(guardianNote, Date.now(), requestId).run();
  return redirect(returnTo);
}

async function handleGuardianCreateCommand(request: Request, env: Env, deviceId: string): Promise<Response> {
  const form = await request.formData();
  const commandType = safeString(form.get("commandType"));
  const targetPackage = nullableString(form.get("targetPackage"));
  let payloadText = nullableString(form.get("payloadText"));
  const returnTo = safeReturnPath(form.get("returnTo"), "/device");
  const allowed = new Set([
    "relock_app",
    "relock_all",
    "enable_protection",
    "panic_protect_all",
    "hide_launcher",
    "show_launcher",
    "enable_risk_shield",
    "disable_risk_shield",
    "start_guard_mode_30",
    "start_guard_mode_60",
    "start_guard_mode_120",
    "start_guard_mode_custom",
    "stop_guard_mode",
    "set_guard_whitelist",
    "set_daily_time_ranges",
    "set_blocked_time_ranges",
    "disable_normal_protection",
    "clear_locked_apps"
  ]);
  if (!allowed.has(commandType)) return html(pageShell("控制失败", renderMessageCard("控制命令无效", "请返回后重新操作。", `<a class="button-link" href="/device">返回设备</a>`), { authenticated: true, activeNav: "device" }), 400);

  if (commandType === "start_guard_mode_custom") {
    const minutes = Number.parseInt(payloadText || "", 10);
    if (!Number.isFinite(minutes) || minutes < 1 || minutes > 1440) {
      return html(pageShell("控制失败", renderMessageCard("时间无效", "自定义守门时间请输入 1 到 1440 分钟。", `<a class="button-link" href="/device">返回设备</a>`), { authenticated: true, activeNav: "device" }), 400);
    }
    payloadText = String(minutes);
  }

  const device = await env.APP_LOCK_DB.prepare("SELECT id FROM app_devices WHERE id = ?").bind(deviceId).first<{ id: string }>();
  if (!device) return html(pageShell("控制失败", renderMessageCard("设备不存在", "请确认手机端已经完成绑定。", `<a class="button-link" href="/device">返回设备</a>`), { authenticated: true, activeNav: "device" }), 404);

  const existing = await env.APP_LOCK_DB.prepare(`
    SELECT id FROM device_commands
    WHERE device_id = ? AND command_type = ? AND COALESCE(target_package, '') = COALESCE(?, '') AND COALESCE(payload_text, '') = COALESCE(?, '') AND status = 'pending'
    LIMIT 1
  `).bind(deviceId, commandType, targetPackage, payloadText).first<{ id: string }>();

  if (!existing) {
    await env.APP_LOCK_DB.prepare(`
      INSERT INTO device_commands (id, device_id, command_type, target_package, payload_text, status, created_at, applied_at)
      VALUES (?, ?, ?, ?, ?, 'pending', ?, NULL)
    `).bind(crypto.randomUUID(), deviceId, commandType, targetPackage, payloadText, Date.now()).run();
  }

  return redirect(returnTo);
}

