async function normalizeStudentGuardState(env: Env, state: StudentMockStateRow): Promise<StudentMockStateRow> {
  if (state.guard_status === "active" && state.guard_end_at && state.guard_end_at <= Date.now()) {
    const now = Date.now();
    await updateStudentState(env, { guard_status: "ended", updated_at: now });
    return { ...state, guard_status: "ended", updated_at: now };
  }
  return state;
}

async function updateStudentState(env: Env, patch: Record<string, unknown>): Promise<void> {
  await getStudentMockStateWithoutNormalize(env);
  const allowed = new Set([
    "student_name", "device_name", "device_model", "device_id",
    "binding_status", "binding_code", "binding_expires_at", "guardian_name", "guardian_relation",
    "guard_status", "guard_mode", "guard_mode_name", "guard_start_at", "guard_end_at",
    "permissions_json", "apps_json", "whitelist_json",
    "device_info_json", "local_guard_json", "service_status_json", "diagnostics_json",
    "last_sync_at", "updated_at"
  ]);
  const entries = Object.entries(patch).filter(([key]) => allowed.has(key));
  if (!entries.length) return;
  const assignments = entries.map(([key]) => `${key} = ?`).join(", ");
  const values = entries.map(([, value]) => value);
  await env.APP_LOCK_DB.prepare(`UPDATE student_mock_state SET ${assignments} WHERE id = ?`).bind(...values, STUDENT_MOCK_STATE_ID).run();
}

