function readStudentPermissions(state: StudentMockStateRow): StudentPermissionItem[] {
  const stored = parseJsonArray<StudentPermissionItem>(state.permissions_json, []);
  const byKey = new Map(STUDENT_DEFAULT_PERMISSIONS.map((item) => [item.key, item]));
  for (const item of stored) {
    const base = byKey.get(item.key);
    if (!base) continue;
    byKey.set(item.key, { ...base, ...item });
  }
  return Array.from(byKey.values());
}

function readStudentApps(state: StudentMockStateRow): StudentMockApp[] {
  return parseJsonArray<StudentMockApp>(state.apps_json, STUDENT_DEFAULT_APPS);
}

function parseJsonArray<T>(value: string, fallback: T[]): T[] {
  try {
    const parsed = JSON.parse(value);
    return Array.isArray(parsed) ? parsed as T[] : fallback;
  } catch {
    return fallback;
  }
}

function studentPermissionsPayload(permissions: StudentPermissionItem[]): Record<string, unknown> {
  const enabledCount = permissions.filter((item) => item.status === "enabled").length;
  const recommendedCount = permissions.filter((item) => item.status === "recommended").length;
  return {
    ok: true,
    total: permissions.length,
    enabledCount,
    recommendedCount,
    permissions,
    source: "last_reported_snapshot",
    note: "这是学生端最近一次上报的权限状态；真实权限需要 Android 本地服务检测。"
  };
}

function normalizeStudentPermissions(value: unknown, fallback: StudentPermissionItem[]): StudentPermissionItem[] {
  if (!Array.isArray(value)) return fallback;
  const nextByKey = new Map(fallback.map((item) => [item.key, item]));
  for (const item of value) {
    if (!item || typeof item !== "object") continue;
    const record = item as Record<string, unknown>;
    const key = safeString(record.key);
    const base = nextByKey.get(key);
    if (!base) continue;
    const status = safeString(record.status);
    nextByKey.set(key, {
      ...base,
      status: status === "enabled" || status === "disabled" || status === "recommended" ? status : base.status
    });
  }
  return Array.from(nextByKey.values());
}

function normalizeStudentApps(value: unknown, fallback: StudentMockApp[]): StudentMockApp[] {
  if (!Array.isArray(value)) return fallback;
  const existing = new Map(fallback.map((app) => [app.packageName, app]));
  for (const item of value) {
    if (!item || typeof item !== "object") continue;
    const record = item as Record<string, unknown>;
    const packageName = safeString(record.packageName);
    if (!packageName) continue;
    const current = existing.get(packageName);
    existing.set(packageName, {
      appId: safeString(record.appId) || current?.appId || packageName,
      packageName,
      name: safeString(record.name) || current?.name || packageName,
      category: safeString(record.category) || current?.category || "其他应用",
      iconUrl: safeString(record.iconUrl) || current?.iconUrl || "/app-icon.svg",
      allowed: typeof record.allowed === "boolean" ? record.allowed : current?.allowed ?? false,
      locked: typeof record.locked === "boolean" ? record.locked : current?.locked ?? false
    });
  }
  return Array.from(existing.values());
}

function studentPermissionSummary(permissions: StudentPermissionItem[]): Record<string, string> {
  const missingRequired = permissions.filter((item) => item.required && item.status !== "enabled").length;
  const recommended = permissions.filter((item) => !item.required && item.status !== "enabled").length;
  if (missingRequired > 0) {
    return { status: "warning", text: "必需权限未完成", description: `还有 ${missingRequired} 项必需权限需要开启` };
  }
  if (recommended > 0) {
    return { status: "good", text: "权限状态良好", description: `已开启必需权限，建议补全 ${recommended} 项加固权限` };
  }
  return { status: "good", text: "权限状态良好", description: "守门服务正在稳定运行" };
}

function studentGuardSnapshot(state: StudentMockStateRow, apps: StudentMockApp[]): Record<string, any> {
  const now = Date.now();
  const active = state.guard_status === "active" && !!state.guard_start_at && !!state.guard_end_at && state.guard_end_at > now;
  const startTime = state.guard_start_at;
  const endTime = state.guard_end_at;
  const durationSeconds = startTime && endTime ? Math.max(1, Math.round((endTime - startTime) / 1000)) : 0;
  const remainingSeconds = active && endTime ? Math.max(0, Math.ceil((endTime - now) / 1000)) : 0;
  const progressPercent = active && durationSeconds > 0 ? Math.min(100, Math.max(0, Math.round(((durationSeconds - remainingSeconds) / durationSeconds) * 100))) : state.guard_status === "ended" ? 100 : 0;
  return {
    guardStatus: active ? "active" : state.guard_status === "ended" ? "ended" : "inactive",
    modeName: state.guard_mode_name,
    mode: state.guard_mode,
    startTime: startTime ? new Date(startTime).toISOString() : null,
    endTime: endTime ? new Date(endTime).toISOString() : null,
    startTimestamp: startTime,
    endTimestamp: endTime,
    remainingSeconds,
    progressPercent,
    allowedAppCount: apps.filter((app) => app.allowed).length,
    lastSyncTime: new Date(state.last_sync_at).toISOString(),
    guardianConnectionStatus: "normal"
  };
}

