function clampStudentDurationMinutes(value: unknown): number {
  const minutes = Number(value ?? 0);
  if (!Number.isFinite(minutes)) return 0;
  const safe = Math.floor(minutes);
  return safe >= 1 && safe <= 1440 ? safe : 0;
}

function formatStudentDuration(seconds: number): string {
  if (seconds <= 0) return "0分钟";
  const minutes = Math.ceil(seconds / 60);
  const hours = Math.floor(minutes / 60);
  const rest = minutes % 60;
  if (hours <= 0) return `${minutes}分钟`;
  if (rest === 0) return `${hours}小时`;
  return `${hours}小时${rest}分钟`;
}

function formatStudentShortDuration(seconds: number): string {
  if (seconds <= 0) return "0m";
  const minutes = Math.ceil(seconds / 60);
  const hours = Math.floor(minutes / 60);
  const rest = minutes % 60;
  if (hours <= 0) return `${minutes}m`;
  return `${hours}h${rest > 0 ? `${rest}m` : ""}`;
}

function relativeStudentTime(timestamp: number): string {
  const diff = Math.max(0, Date.now() - timestamp);
  const minutes = Math.floor(diff / 60_000);
  if (minutes <= 0) return "刚刚";
  if (minutes < 60) return `${minutes}分钟前`;
  const hours = Math.floor(minutes / 60);
  if (hours < 24) return `${hours}小时前`;
  return formatAppTime(timestamp);
}

