async function requireGuardianSession(request: Request, env: Env, next: () => Promise<Response>): Promise<Response> {
  const session = await getGuardianSession(request, env);
  if (!session) return redirect("/login");
  return next();
}

async function getGuardianSession(request: Request, env: Env): Promise<{ id: string } | null> {
  const sessionId = getCookie(request.headers.get("Cookie") || "", SESSION_COOKIE);
  if (!sessionId) return null;
  return await env.APP_LOCK_DB.prepare("SELECT id FROM guardian_sessions WHERE id = ? AND expires_at > ?").bind(sessionId, Date.now()).first<{ id: string }>();
}

async function authenticateDevice(env: Env, deviceId: string, deviceSecret: string): Promise<{ id: string } | null> {
  if (!deviceId || !deviceSecret) return null;
  const device = await env.APP_LOCK_DB.prepare("SELECT id, device_secret FROM app_devices WHERE id = ?").bind(deviceId).first<DeviceRow>();
  if (!device || device.device_secret !== deviceSecret) return null;
  await env.APP_LOCK_DB.prepare("UPDATE app_devices SET last_seen_at = ? WHERE id = ?").bind(Date.now(), deviceId).run();
  return { id: device.id };
}

async function hasGuardianAccount(env: Env): Promise<boolean> {
  const account = await env.APP_LOCK_DB.prepare("SELECT id FROM guardian_account WHERE id = 1").first<{ id: number }>();
  return !!account;
}

async function readJsonObject(request: Request): Promise<Record<string, unknown>> {
  const text = await request.text();
  if (!text) return {};
  const parsed = JSON.parse(text) as unknown;
  if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) throw new Error("request_body_must_be_json_object");
  return parsed as Record<string, unknown>;
}

async function hashPassword(password: string, salt: string): Promise<string> {
  const encoder = new TextEncoder();
  const digest = await crypto.subtle.digest("SHA-256", encoder.encode(`${salt}:${password}`));
  return base64Encode(digest);
}

function base64Encode(buffer: ArrayBuffer): string {
  let binary = "";
  for (const byte of new Uint8Array(buffer)) binary += String.fromCharCode(byte);
  return btoa(binary);
}

function randomToken(byteLength: number): string {
  const bytes = new Uint8Array(byteLength);
  crypto.getRandomValues(bytes);
  return Array.from(bytes, (byte) => byte.toString(16).padStart(2, "0")).join("");
}

function getCookie(header: string, name: string): string | null {
  for (const part of header.split(";").map((item) => item.trim())) if (part.startsWith(`${name}=`)) return decodeURIComponent(part.slice(name.length + 1));
  return null;
}

