function renderAppIcon(label: string | null, packageName: string | null): string {
  const key = `${label || ""} ${packageName || ""}`.toLowerCase();
  if (key.includes("王者") || key.includes("honor") || key.includes("tmgp")) {
    return `<span class="app-icon game" aria-hidden="true"><b>5v5</b><i></i><em></em><strong></strong></span>`;
  }
  if (key.includes("抖音") || key.includes("douyin") || key.includes("tiktok")) {
    return `<span class="app-icon douyin" aria-hidden="true"><b>♪</b><i></i></span>`;
  }
  if (key.includes("设置") || key.includes("settings")) {
    return `<span class="app-icon settings-icon" aria-hidden="true">${icon("settings")}</span>`;
  }
  const letter = (label || packageName || "守").trim().slice(0, 1).toUpperCase();
  return `<span class="app-icon default-icon" aria-hidden="true"><b>${escapeHtml(letter)}</b></span>`;
}

