function friendlyDeviceName(name: string): string {
  const value = name.trim();
  if (!value) return "当前手机";
  if (/^\d{4,}[A-Z0-9_-]{3,}$/i.test(value)) return "红米手机";
  if (/^[A-Z0-9_-]{8,}$/i.test(value) && !/[一-龥]/.test(value)) return "当前手机";
  return value;
}

function deviceModelName(device: DeviceRow): string {
  const raw = device.device_name.trim();
  if (raw && raw !== friendlyDeviceName(raw)) return raw;
  return device.id.length > 12 ? device.id.slice(0, 12) : device.id;
}

function fullDeviceTitle(device: DeviceRow): string {
  return `${friendlyDeviceName(device.device_name)}（设备：${deviceModelName(device)}）`;
}

function formatAppTime(timestamp: number): string {
  const date = new Date(timestamp);
  const now = new Date();
  const sameDay = date.toDateString() === now.toDateString();
  const yesterday = new Date(now);
  yesterday.setDate(now.getDate() - 1);
  const clock = date.toLocaleTimeString("zh-CN", { hour: "2-digit", minute: "2-digit", hour12: false });
  if (sameDay) return `今天 ${clock}`;
  if (date.toDateString() === yesterday.toDateString()) return `昨天 ${clock}`;
  return `${date.getMonth() + 1}/${date.getDate()} ${clock}`;
}

function appTitle(row: UnlockRequestRow): string {
  return row.target_label || requestTypeLabel(row.request_type);
}

function remainingMinutes(row: UnlockRequestRow): number {
  if (row.approved_mode === "today") return 24 * 60;
  if (!row.decided_at) return row.approved_minutes || DEFAULT_APPROVE_MINUTES;
  const minutes = row.approved_minutes ?? DEFAULT_APPROVE_MINUTES;
  return Math.max(0, Math.ceil((row.decided_at + minutes * 60_000 - Date.now()) / 60_000));
}

function shortRelativeTime(timestamp: number): string {
  const minutes = Math.max(0, Math.round((Date.now() - timestamp) / 60_000));
  if (minutes < 1) return "刚刚";
  if (minutes < 60) return `${minutes} 分钟前`;
  return shortClock(timestamp);
}

function shortClock(timestamp: number): string {
  return new Date(timestamp).toLocaleTimeString("zh-CN", { hour: "2-digit", minute: "2-digit", hour12: false });
}

function commandIcon(commandType: string): string {
  if (commandType.includes("launcher")) return "grid";
  if (commandType.includes("risk")) return "lock";
  if (commandType.includes("guard_mode")) return "clock";
  if (commandType.includes("relock") || commandType.includes("protect")) return "shield";
  return "phone";
}

function isHiddenCommand(commandType: string): boolean {
  return commandType.includes("deepseek") || commandType === "report_device_owner_status";
}

function isHiddenCommandRow(row: DeviceCommandRow): boolean {
  const raw = `${row.command_type} ${row.payload_text || ""} ${row.result_message || ""}`.toLowerCase();
  return raw.includes("deepseek") || row.command_type === "report_device_owner_status";
}

