function parentApiClientBaseScript(): string {
  return `<script>
function parentEscape(value) {
  return String(value == null ? "" : value).replace(/[&<>"']/g, function(ch) {
    return ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;" })[ch];
  });
}
function parentSet(id, html) {
  var node = document.getElementById(id);
  if (node) node.innerHTML = html;
}
function parentLoading(text) {
  return '<article class="empty-state soft-empty"><h3>' + parentEscape(text) + '</h3><p>请稍等...</p></article>';
}
function parentEmpty(title, text) {
  return '<article class="empty-state soft-empty"><h3>' + parentEscape(title) + '</h3><p>' + parentEscape(text || '') + '</p></article>';
}
function parentError(text) {
  return '<article class="empty-state soft-empty"><h3>读取失败</h3><p>' + parentEscape(text || '请稍后重试') + '</p><button class="button-link secondary" type="button" onclick="location.reload()">重试</button></article>';
}
async function parentFetchJson(path, options) {
  var response = await fetch(path, Object.assign({ headers: { "accept": "application/json", "content-type": "application/json" } }, options || {}));
  var payload = null;
  try { payload = await response.json(); } catch (error) {}
  if (!response.ok || (payload && payload.ok === false)) {
    throw new Error((payload && (payload.message || payload.error)) || ('请求失败：' + response.status));
  }
  return payload || {};
}
function parentRequestCard(request, withActions) {
  var status = request.status || 'pending';
  var reason = request.reason || request.requestReason || '未填写原因';
  var minutes = request.durationMinutes || request.requestMinutes || 0;
  var submitted = request.submittedAtText || request.requestTime || request.submittedAt || '';
  var actions = withActions ? '<div class="button-row"><button class="primary" data-action="approve" data-id="' + parentEscape(request.requestId || request.id) + '">同意</button><button class="danger" data-action="reject" data-id="' + parentEscape(request.requestId || request.id) + '">拒绝</button></div>' : '';
  return '<article class="app-card request-card"><header><div><span class="status-pill ' + parentEscape(status) + '">' + parentEscape(status) + '</span><h3>' + parentEscape(request.appName || request.appId || '临时放行') + '</h3><p>' + parentEscape(minutes) + ' 分钟 · ' + parentEscape(submitted) + '</p></div></header><p class="muted">' + parentEscape(reason) + '</p>' + actions + '<p class="muted" data-message-for="' + parentEscape(request.requestId || request.id) + '"></p></article>';
}
function parentCommandRow(command) {
  var status = command.commandStatus || command.rawStatus || 'pending';
  var created = command.createdAt || '';
  return '<article class="list-row command-row"><span class="command-icon"></span><div><span class="status-pill ' + parentEscape(status) + '">' + parentEscape(status) + '</span><h3>' + parentEscape(command.commandLabel || command.commandType || '命令') + '</h3><p>' + parentEscape(created) + (command.resultMessage ? ' · ' + parentEscape(command.resultMessage) : '') + '</p></div></article>';
}
function parentAppPill(app) {
  return '<article class="list-row"><div><h3>' + parentEscape(app.name || app.appName || app.packageName || app.appId) + '</h3><p>' + parentEscape(app.packageName || app.appPackage || app.appId || '') + '</p></div></article>';
}
</script>`;
}

