function replaceHistoryScript(): string {
  return `<script>
if ("serviceWorker" in navigator) { navigator.serviceWorker.register("/sw.js").catch(function () {}); }
if (window.history && window.history.replaceState) { window.history.replaceState(null, "", window.location.pathname + window.location.search); }
document.addEventListener("submit", function(event) {
  const form = event.target;
  if (!form || !form.querySelector) return;
  const button = form.querySelector("button[type=submit]");
  if (!button || button.dataset.submitting === "1") return;
  button.dataset.submitting = "1";
  button.setAttribute("aria-busy", "true");
  setTimeout(function() {
    if (button.closest(".decision-form, .toggle-form")) button.textContent = "已发送，等待手机拉取";
    else button.textContent = "正在提交";
    button.disabled = true;
  }, 0);
}, true);
</script>`;
}

function installPromptScript(): string {
  return `<script>
let deferredInstallPrompt = null;
function installHintText() {
  const ua = navigator.userAgent || "";
  if (/MicroMessenger/i.test(ua)) return "微信不支持网页按钮直接安装，请点右上角菜单，或用系统浏览器打开后添加到桌面。";
  return "如果没有弹出安装提示，请用浏览器菜单里的添加到桌面或安装应用。";
}
window.addEventListener("beforeinstallprompt", function(event) {
  event.preventDefault();
  deferredInstallPrompt = event;
});
document.addEventListener("click", function(event) {
  const button = event.target && event.target.closest ? event.target.closest(".install-button") : null;
  if (!button) return;
  if (deferredInstallPrompt) {
    deferredInstallPrompt.prompt();
    deferredInstallPrompt = null;
    button.textContent = "已打开安装提示";
    return;
  }
  button.textContent = "查看添加方法";
  const hint = button.parentElement ? button.parentElement.querySelector("small") : null;
  if (hint) hint.textContent = installHintText();
});
document.addEventListener("submit", function(event) {
  const form = event.target;
  if (!form || !form.querySelector) return;
  const button = form.querySelector("button[type=submit]");
  if (!button || button.dataset.submitting === "1") return;
  button.dataset.submitting = "1";
  button.setAttribute("aria-busy", "true");
  setTimeout(function() {
    button.textContent = button.closest(".decision-form, .toggle-form") ? "已发送，等待手机拉取" : "正在提交";
    button.disabled = true;
  }, 0);
}, true);
</script>`;
}

function approvalSummary(row: UnlockRequestRow): string {
  if (row.approved_mode === "today") return "今天都允许";
  if (row.approved_minutes && row.approved_minutes > 0) return `批准 ${row.approved_minutes} 分钟`;
  return `批准 ${DEFAULT_APPROVE_MINUTES} 分钟`;
}

function approvalRemaining(row: UnlockRequestRow): string {
  if (row.approved_mode === "today") return "今天有效";
  if (!row.decided_at) return "刚刚批准";
  const minutes = row.approved_minutes ?? DEFAULT_APPROVE_MINUTES;
  const remaining = Math.max(0, Math.ceil((row.decided_at + minutes * 60_000 - Date.now()) / 60_000));
  return `还剩 ${remaining} 分钟`;
}

function isApprovalStillActive(row: UnlockRequestRow): boolean {
  if (row.status !== "approved" || !row.decided_at) return false;
  const now = Date.now();
  if (row.approved_mode === "today") {
    const end = new Date();
    end.setHours(23, 59, 59, 999);
    return now < end.getTime();
  }
  const minutes = row.approved_minutes ?? DEFAULT_APPROVE_MINUTES;
  return now < row.decided_at + minutes * 60_000;
}

function requestTypeLabel(requestType: string): string {
  if (requestType === "unlock_app") return "解锁应用";
  if (requestType === "settings_access") return "进入应用管理";
  if (requestType === "pause_protection") return "暂停保护";
  return requestType;
}

function commandTypeLabel(commandType: string): string {
  if (commandType === "set_blocked_time_ranges") return "设置今日禁止时段";
  if (commandType === "relock_app") return "重新保护单个应用";
  if (commandType === "relock_all") return "重新保护所有已放行应用";
  if (commandType === "enable_protection") return "开启保护";
  if (commandType === "panic_protect_all") return "一键重新收紧";
  if (commandType === "show_launcher") return "显示桌面图标";
  if (commandType === "hide_launcher") return "隐藏桌面图标";
  if (commandType === "enable_risk_shield") return "开启强力模式";
  if (commandType === "disable_risk_shield") return "关闭强力模式";
  if (commandType === "start_guard_mode_30") return "守门模式 30 分钟";
  if (commandType === "start_guard_mode_60") return "守门模式 1 小时";
  if (commandType === "start_guard_mode_120") return "守门模式 2 小时";
  if (commandType === "start_guard_mode_custom") return "守门模式自定义时间";
  if (commandType === "stop_guard_mode") return "结束守门模式";
  if (commandType === "set_guard_whitelist") return "设置守门白名单";
  if (commandType === "set_daily_time_ranges") return "设置每日可用时间段";
  if (commandType === "app_block") return "限制单个应用";
  if (commandType === "app_unblock") return "解除单个应用限制";
  if (commandType === "disable_normal_protection") return "关闭普通保护";
  if (commandType === "clear_locked_apps") return "清空限制名单";
  return commandType;
}

function statusLabel(status: string): string {
  if (status === "approved") return "已批准";
  if (status === "rejected") return "已拒绝";
  if (status === "pending") return "待审批";
  return status;
}

function statusTone(status: string): string {
  if (status === "approved") return "approved";
  if (status === "rejected") return "rejected";
  if (status === "pending") return "pending";
  return "neutral";
}

function safeReturnPath(value: unknown, fallback: string): string {
  const path = safeString(value);
  if (path === "/" || path === "/device" || path === "/requests" || path === "/rules" || path === "/report" || path === "/me" || path === "/password" || path === "/active") return path;
  if (/^\/device\?deviceId=[A-Za-z0-9._~!$&'()*+,;=:@%-]+$/.test(path)) return path;
  if (/^\/request\/[^/]+$/.test(path)) return path;
  return fallback;
}

function baseUrl(request: Request): string {
  const url = new URL(request.url);
  return `${url.protocol}//${url.host}`;
}

function pageShell(title: string, content: string, options: PageShellOptions = {}): string {
  const className = options.pageClass ? ` ${options.pageClass}` : "";
  const nav = options.authenticated ? renderBottomNav(options.activeNav || "home") : "";
  return `<!doctype html><html lang="zh-CN"><head><meta charset="utf-8" /><meta name="viewport" content="width=device-width, initial-scale=1, viewport-fit=cover" /><title>${escapeHtml(title)}</title><link rel="manifest" href="/manifest.webmanifest" /><meta name="theme-color" content="${THEME_COLOR}" /><meta name="apple-mobile-web-app-capable" content="yes" /><meta name="apple-mobile-web-app-title" content="${APP_NAME}" /><meta name="apple-mobile-web-app-status-bar-style" content="default" /><style>${GLOBAL_CSS}</style></head><body class="${className.trim()}"><main class="app-shell">${content}</main>${nav}</body></html>`;
}

function renderBottomNav(active: NavItem): string {
  const items: Array<{ id: NavItem; href: string; label: string; iconName: string }> = [
    { id: "home", href: "/", label: "首页", iconName: "home" },
    { id: "device", href: "/device", label: "设备", iconName: "phone" },
    { id: "me", href: "/me", label: "我的", iconName: "user" }
  ];
  return `<nav class="bottom-nav" aria-label="主导航">${items.map((item) => `<a class="${active === item.id ? "active" : ""}" href="${item.href}">${icon(item.iconName)}<span>${item.label}</span></a>`).join("")}</nav>`;
}

function html(content: string, status = 200, headers: HeadersInit = {}): Response {
  return new Response(content, { status, headers: { "content-type": "text/html; charset=utf-8", ...CACHE_HEADERS, ...headers } });
}

function json(payload: unknown, status = 200, headers: HeadersInit = {}): Response {
  return new Response(JSON.stringify(payload), { status, headers: { "content-type": "application/json; charset=utf-8", ...CACHE_HEADERS, ...headers } });
}

function redirect(location: string, headers: HeadersInit = {}): Response {
  return new Response(null, { status: 302, headers: { Location: location, ...CACHE_HEADERS, ...headers } });
}

function safeString(value: unknown): string {
  return typeof value === "string" ? value.trim() : "";
}

function isPlainRecord(value: unknown): value is Record<string, unknown> {
  return !!value && typeof value === "object" && !Array.isArray(value);
}

function numberOrNull(value: unknown): number | null {
  const numberValue = Number(value);
  return Number.isFinite(numberValue) && numberValue > 0 ? Math.floor(numberValue) : null;
}

function nullableString(value: unknown): string | null {
  const normalized = safeString(value);
  return normalized || null;
}

function clampMinutes(value: unknown): number {
  const minutes = Number(value ?? 0);
  if (!Number.isFinite(minutes)) return 0;
  const safe = Math.floor(minutes);
  return safe < 1 || safe > MAX_APPROVE_MINUTES ? 0 : safe;
}

function formatTime(timestamp: number): string {
  return formatAppTime(timestamp);
}

function escapeHtml(value: string): string {
  return value.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;").replace(/'/g, "&#39;");
}

